import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  Alert, Box, Button, CircularProgress, Container, Stack,
  TextField, Typography,
} from '@mui/material';
import { AutoStories, Google, Apple, Email } from '@mui/icons-material';
import { useAuth } from '../contexts/AuthContext';

const RegisterPage = () => {
  const { register } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setForm((prev) => ({ ...prev, [e.target.name]: e.target.value }));
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.name || !form.email || !form.password) {
      setError('Please fill in all fields.');
      return;
    }
    if (form.password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }
    setLoading(true);
    try {
      await register(form.name, form.email, form.password);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', py: 3, px: 2 }}>
      <Container maxWidth="xs" disableGutters>
        <Box sx={{ bgcolor: 'rgba(255,255,255,0.9)', borderRadius: 7, p: 3, boxShadow: 4, border: '1px solid rgba(232,225,247,0.9)' }}>
          <Box sx={{ textAlign: 'center', mb: 3 }}>
            <Box sx={{ width: 68, height: 68, mx: 'auto', mb: 1.5, borderRadius: 5, display: 'grid', placeItems: 'center', color: 'white', background: 'linear-gradient(135deg, #7C3AED, #2563EB, #06B6D4)', boxShadow: '0 18px 34px rgb(124 58 237 / 0.28)' }}>
              <AutoStories sx={{ fontSize: 36 }} />
            </Box>
            <Typography variant="h3">Welcome to FLIP</Typography>
            <Typography variant="body2" color="text.secondary">
              Create your account and start your journey.
            </Typography>
          </Box>

          {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

          <Box component="form" onSubmit={handleSubmit}>
            <Stack spacing={1.5}>
              <TextField label="Full name" name="name" value={form.name} onChange={handleChange} fullWidth autoFocus />
              <TextField label="Email address" name="email" type="email" value={form.email} onChange={handleChange} fullWidth />
              <TextField label="Password" name="password" type="password" value={form.password} onChange={handleChange} fullWidth helperText="At least 6 characters" />
              <Button type="submit" variant="contained" size="large" fullWidth disabled={loading} startIcon={!loading ? <Email /> : null}>
                {loading ? <CircularProgress size={20} color="inherit" /> : 'Create Account'}
              </Button>
            </Stack>
          </Box>

          <Stack direction="row" spacing={1.25} sx={{ mt: 2 }}>
            <Button variant="outlined" fullWidth sx={{ minWidth: 0, color: 'text.primary' }}><Apple /></Button>
            <Button variant="outlined" fullWidth sx={{ minWidth: 0, color: 'text.primary' }}><Google /></Button>
            <Button variant="outlined" fullWidth sx={{ minWidth: 0, color: 'text.primary' }}><Email /></Button>
          </Stack>

          <Typography variant="body2" color="text.secondary" sx={{ mt: 2.5, textAlign: 'center' }}>
            Already have an account?{' '}
            <Link to="/login" style={{ color: '#7C3AED', fontWeight: 900, textDecoration: 'none' }}>
              Log in
            </Link>
          </Typography>
        </Box>
      </Container>
    </Box>
  );
};

export default RegisterPage;
